import api from './api';

export const cartItemService = {
  getItemsByCartId: async (cartId) => (await api.get(`/api/cart-items/cart/${cartId}`)).data,
  addCartItem: async (item) => (await api.post('/api/cart-items', item)).data,
  updateCartItem: async (id, item) => (await api.put(`/api/cart-items/${id}`, item)).data,
  removeCartItem: async (id) => (await api.delete(`/api/cart-items/${id}`)).data,
};
